function stripUrl(url){if(!url)return null;return typeof url==='string'&&url.includes('?')?url.split('?')[0]:url;}
function normHandle(raw){if(!raw||typeof raw!=='string')return null;return raw.replace(/^@/,'').toLowerCase().trim();}
function fmtFollowers(n){if(n==null)return null;if(n>=1000000)return`${(n/1000000).toFixed(1)}M`;if(n>=1000)return`${(n/1000).toFixed(0)}K`;return`${n}`;}
function growthTrend(g){if(!g||typeof g!=='object')return null;const vals=[g['12_months_ago'],g['9_months_ago'],g['6_months_ago'],g['3_months_ago']].filter(v=>typeof v==='number');if(vals.length<2)return null;return vals[vals.length-1]>vals[0]?'accelerating':'decelerating';}
function buildLinks(ch,handle){const l={};if(!handle)return l;if(Array.isArray(ch)){ch.forEach(e=>{if(e&&typeof e==='object')Object.entries(e).forEach(([p,u])=>{if(u)l[p]=u;});});}else if(ch&&typeof ch==='object'){if(ch.has_instagram||ch.instagram)l.instagram=`https://www.instagram.com/${handle}`;if(ch.has_tiktok)l.tiktok=`https://www.tiktok.com/@${handle}`;if(ch.has_youtube)l.youtube=`https://www.youtube.com/@${handle}`;if(ch.has_twitter)l.twitter=`https://twitter.com/${handle}`;if(ch.has_linktree)l.linktree=`https://linktr.ee/${handle}`;}return l;}
function dedupCollabs(tagged){if(!Array.isArray(tagged))return[];const c={};tagged.forEach(t=>{if(t?.username)c[t.username]=(c[t.username]||0)+1;});return Object.entries(c).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([u])=>u);}

function normalize(entry) {
  // FIX: unwrap the "result" wrapper
  const raw = entry.result || entry;
  const ig = raw.instagram || {};

  const handle = normHandle(ig?.username || ig?.handle || raw?.creator_handle);
  const userId = ig?.userid || ig?.user_id || raw?.user_id || null;
  const email = raw?.email || raw?.contact_email || ig?.email || null;
  const followers = ig?.follower_count ?? ig?.followers ?? null;
  const engPct = ig?.engagement_percent ?? null;
  const avgLikes = ig?.avg_likes ?? ig?.average_likes ?? null;
  const avgComments = ig?.avg_comments ?? ig?.average_comments ?? null;
  const ctlRatio = (typeof avgLikes==='number'&&avgLikes>0&&typeof avgComments==='number') ? parseFloat(((avgComments/avgLikes)*100).toFixed(2)) : null;
  const ch = raw?.creator_has || ig?.creator_has || null;
  const xp = buildLinks(ch, handle);
  if(handle && !xp.instagram) xp.instagram = `https://www.instagram.com/${handle}`;
  const lt = ig?.linktree || raw?.linktree || null;
  if(lt && !xp.linktree) xp.linktree = `https://linktr.ee/${lt}`;
  const gr = ig?.creator_follower_growth || null;
  const fg = gr ? {'3_months_ago_pct':gr['3_months_ago']??null,'6_months_ago_pct':gr['6_months_ago']??null,'9_months_ago_pct':gr['9_months_ago']??null,'12_months_ago_pct':gr['12_months_ago']??null,trend:growthTrend(gr)} : null;
  const aud = {
    follower_count: followers,
    follower_count_fmt: fmtFollowers(followers),
    following_count: ig?.following_count ?? null,
    media_count: ig?.media_count ?? null,
    top_country: ig?.country || raw?.location || null,
    state: ig?.state || null,
    city: ig?.city || null,
    location_certainty: ig?.location_certainty ?? null,
    language: Array.isArray(ig?.language_code) ? ig.language_code[0] : (raw?.speaking_language || ig?.language_code || null)
  };
  const collabs = dedupCollabs(ig?.tagged || []).filter(u => u !== handle);
  const locs = [...new Set((ig?.locations || []).filter(Boolean))].slice(0,5);
  const incRaw = ig?.income || raw?.income_data?.instagram || null;
  const inc = incRaw ? {min_usd:incRaw.min??null,max_usd:incRaw.max??null,currency:incRaw.currency??null} : null;
  let tags = [];
  if(Array.isArray(ig?.hashtags_count) && ig.hashtags_count.length){
    tags = ig.hashtags_count.sort((a,b)=>b.count-a.count).slice(0,10).map(h=>h.name);
  } else if(Array.isArray(ig?.hashtags)){
    const seen = new Set();
    tags = ig.hashtags.filter(h=>h&&h.length>1&&!seen.has(h)&&seen.add(h)).slice(0,10);
  }
  const dk = handle ? `instagram:${handle}` : userId ? `instagram:${userId}` : null;

  return {
    normalized_profile: {
      identity: {
        user_id: userId,
        full_name: ig?.full_name || raw?.first_name || null,
        handle,
        display_handle: handle ? `@${handle}` : null,
        platform_primary: 'instagram',
        profile_url: handle ? `https://www.instagram.com/${handle}` : null,
        profile_picture: stripUrl(ig?.profile_picture || ig?.profile_picture_hd),
        email,
        is_verified: ig?.is_verified ?? false,
        is_private: ig?.is_private ?? false,
        is_business_account: ig?.is_business_account ?? raw?.is_business ?? false,
        account_type: raw?.is_creator ? 'creator' : (ig?.account_type === 3 ? 'creator' : 'personal'),
        category: ig?.category || null,
        niche_topics: ig?.niche_class || []
      },
      cross_platform_links: xp,
      contact: {
        email,
        email_type: raw?.email_type || null,
        phone: raw?.contact_phone_number ? `+${String(raw.contact_phone_number).replace(/^\+/,'')}` : (ig?.contact_phone_number || null),
        has_link_in_bio: ig?.uses_link_in_bio ?? raw?.has_link_in_bio ?? false,
        bio_links: ig?.links_in_bio || raw?.links_in_bio || []
      },
      audience: aud,
      follower_growth: fg,
      engagement: {
        engagement_percent: engPct,
        avg_likes: avgLikes,
        avg_comments: avgComments,
        median_likes: ig?.likes_median ?? null,
        median_comments: ig?.comments_median ?? null,
        comment_to_like_ratio_pct: ctlRatio
      },
      content: {
        posting_frequency_per_month: ig?.posting_frequency_recent_months ?? null,
        reels_percentage: ig?.reels_percentage_last_12_posts ?? null,
        video_content_creator: ig?.video_content_creator ?? false,
        most_recent_post_date: ig?.most_recent_post_date || null,
        top_hashtags: tags,
        biography: ig?.biography || null
      },
      monetization: {
        has_brand_deals: raw?.has_brand_deals ?? ig?.has_done_brand_deals ?? false,
        has_merch: ig?.has_merch ?? false,
        promotes_affiliate_links: ig?.promotes_affiliate_links ?? false,
        estimated_income: inc
      },
      network: {
        frequent_collaborators: collabs,
        primary_locations: locs
      },
      flags: {
        low_engagement: typeof engPct==='number' && typeof followers==='number' && engPct<1.0 && followers>10000,
        tiktok_id_only: !!(xp.tiktok && /\/\d{10,}/.test(xp.tiktok))
      },
      dedup_key: dk
    }
  };
}

