// ── Find creator with highest estimated_reach_per_post.high ──

const allData = items[0].json.data;
const creators = Array.isArray(allData) ? allData : [];

let topHandle = null;
let topReach = -1;

creators.forEach(item => {
  const reach = item?.output?.estimated_reach_per_post?.high ?? 0;
  const handle = item?.output?.handle ?? null;

  if (reach > topReach && handle) {
    topReach = reach;
    topHandle = handle;
  }
});

// Fallback if no valid result found
if (!topHandle && creators.length > 0) {
  topHandle = creators[0]?.output?.handle ?? 'unknown';
  topReach = creators[0]?.output?.estimated_reach_per_post?.high ?? 0;
}

return [
  {
    json: {
      lookalike_seed_handle: topHandle || 'unknown',
      seed_reach_high: topReach
    }
  }
];

